import copy

class BfsSolver:
    def train(self,problem):
        self.problem = problem

    def solve(self):
        node = self.__search()
        return node.getActions() if node else None

    def __search(self):
        initNode = Node(self.problem.getState(),0,None,None)
        frontiers = [initNode]

        reached = {tuple(initNode.state):initNode}

        while len(frontiers):
            node = frontiers.pop(0)
            if node.state == self.problem.goal:
                return node
            for childNode in self.expand(node):
                state = childNode.state
                if tuple(state) not in reached or childNode.cost < reached[tuple(state)].cost:
                    reached[tuple(state)] = childNode
                    frontiers.append(childNode)
        return None

    def getProblemAfterAction(self,actions):
        problem = copy.deepcopy(self.problem)
        problem.action(actions)
        return problem

    def expand(self,node):
        actions = node.getActions()
        problem = self.getProblemAfterAction(actions)
        posActions = problem.getPosActions()

        for action in posActions:
            cost = problem.cost(action)

            problem.action([action])

            curState = problem.getState()
            yield Node(curState,node.cost + cost,node,action)

            problem = self.getProblemAfterAction(actions)
